parameters.jsonBody:
={
  "contents": [
    {
      "parts": [
        {
          "fileData": {
            "mimeType": "{{ $json.file.mimeType }}",
            "fileUri": "{{ $json.file.uri }}"
          }
        },
        {
          "text": "Analyze this phone call recording and evaluate it as a sales/telemarketing call.\n\nDetermine:\n- How far the call got (one of: Contact reached / Needs identified / Meeting proposed / Appointment booked)\n- Specific, actionable advice for the caller\n\nReturn ONLY valid JSON, no other text."
        }
      ]
    }
  ],
  "generationConfig": {
    "responseMimeType": "application/json",
    "responseSchema": {
      "type": "object",
      "properties": {
        "step": {
          "type": "string",
          "description": "Stage reached in the call (Contact reached / Needs identified / Meeting proposed / Appointment booked)"
        },
        "advice": {
          "type": "string",
          "description": "Specific advice for improving the call"
        }
      },
      "required": ["step", "advice"]
    }
  }
}
